import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate, Toggle } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('AuctionScene')
export class AuctionScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Toggle)
    biddingTab: Toggle = null;
    
    @property(Toggle)
    fixedTab: Toggle = null;
    
    @property(Toggle)
    darkTab: Toggle = null;
    
    @property(ScrollView)
    itemListScrollView: ScrollView = null;
    
    @property(Node)
    auctionItemPrefab: Node = null;
    
    @property(Node)
    sellPanel: Node = null;
    
    @property(Button)
    sellBtn: Button = null;
    
    private currentTab: string = 'bidding';
    
    // 模拟拍卖数据
    private auctionItems = [
        { id: 1, name: '传说拂尘', type: 'equipment', quality: 'legendary', currentPrice: 5000, buyoutPrice: 10000, bidder: '玩家A', timeLeft: 300, seller: '玩家B' },
        { id: 2, name: '金身战甲', type: 'equipment', quality: 'epic', currentPrice: 3000, buyoutPrice: 6000, bidder: null, timeLeft: 600, seller: '玩家C' },
        { id: 3, name: '财神护符', type: 'accessory', quality: 'legendary', currentPrice: 8000, buyoutPrice: 15000, bidder: '玩家D', timeLeft: 120, seller: '玩家E' }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.sellBtn.node.on(Button.EventType.CLICK, this.onSell, this);
        this.biddingTab.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('bidding'), this);
        this.fixedTab.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('fixed'), this);
        this.darkTab.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('dark'), this);
    }
    
    start() {
        this.updateItemList();
        this.schedule(this.updateCountdown, 1);
    }
    
    onTabChange(tab: string) {
        this.currentTab = tab;
        this.updateItemList();
    }
    
    updateItemList() {
        const content = this.itemListScrollView.content;
        content.removeAllChildren();
        
        for (const item of this.auctionItems) {
            const node = instantiate(this.auctionItemPrefab);
            
            node.getChildByName('NameLabel').getComponent(Label).string = item.name;
            node.getChildByName('QualityLabel').getComponent(Label).string = item.quality;
            node.getChildByName('CurrentPriceLabel').getComponent(Label).string = `当前: ${item.currentPrice}`;
            node.getChildByName('BuyoutLabel').getComponent(Label).string = `一口价: ${item.buyoutPrice}`;
            node.getChildByName('BidderLabel').getComponent(Label).string = item.bidder ? `出价: ${item.bidder}` : '无人出价';
            node.getChildByName('TimeLabel').getComponent(Label).string = this.formatTime(item.timeLeft);
            
            // 出价按钮
            const bidBtn = node.getChildByName('BidBtn').getComponent(Button);
            bidBtn.node.on(Button.EventType.CLICK, () => this.onBid(item), this);
            
            // 一口价按钮
            const buyoutBtn = node.getChildByName('BuyoutBtn').getComponent(Button);
            buyoutBtn.node.on(Button.EventType.CLICK, () => this.onBuyout(item), this);
            
            content.addChild(node);
        }
    }
    
    updateCountdown() {
        for (const item of this.auctionItems) {
            if (item.timeLeft > 0) {
                item.timeLeft--;
            }
        }
        this.updateItemList();
    }
    
    formatTime(seconds: number): string {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    }
    
    onBid(item: any) {
        const bidAmount = item.currentPrice + 100;
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency('yuanbao', bidAmount)) {
            console.log('元宝不足');
            return;
        }
        
        item.currentPrice = bidAmount;
        item.bidder = '我';
        this.updateItemList();
        console.log(`出价成功: ${bidAmount}`);
    }
    
    onBuyout(item: any) {
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency('yuanbao', item.buyoutPrice)) {
            console.log('元宝不足');
            return;
        }
        
        // 购买成功
        console.log(`一口价购买成功: ${item.name}`);
        // 从列表移除
        const index = this.auctionItems.indexOf(item);
        if (index > -1) {
            this.auctionItems.splice(index, 1);
        }
        this.updateItemList();
    }
    
    onSell() {
        this.sellPanel.active = true;
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
    
    onDestroy() {
        this.unschedule(this.updateCountdown);
    }
}
